        // ── Gallery System ─────────────────────────────────────────────────────
        const GALLERY_KEY = 'lucky3-gallery-v1';
        const DAILY_WINS_KEY = 'lucky3-daily-wins-v1';

        const PAINTINGS = [
            { id:'001', cols:3, rows:4 },
            { id:'002', cols:4, rows:3 },
            { id:'003', cols:3, rows:3 }
        ];

        function loadGalleryData() {
            try {
                const raw = localStorage.getItem(GALLERY_KEY);
                if (!raw) return {};
                return JSON.parse(raw);
            } catch (_) { return {}; }
        }

        function saveGalleryData(data) {
            try { localStorage.setItem(GALLERY_KEY, JSON.stringify(data)); } catch (_) {}
        }

        function loadDailyWins() {
            try {
                const raw = localStorage.getItem(DAILY_WINS_KEY);
                if (!raw) return { date: '', count: 0 };
                return JSON.parse(raw);
            } catch (_) { return { date: '', count: 0 }; }
        }

        function recordDailyWin() {
            const today = toLocalDateKey();
            const dw = loadDailyWins();
            if (dw.date !== today) dw.count = 0;
            dw.date = today;
            dw.count += 1;
            try { localStorage.setItem(DAILY_WINS_KEY, JSON.stringify(dw)); } catch (_) {}
            return dw.count;
        }

        function dropFragment() {
            const data = loadGalleryData();
            // 收集所有尚未收集的碎片
            const uncollected = [];
            for (const p of PAINTINGS) {
                const total = p.cols * p.rows;
                const collected = new Set(data[p.id]?.collected || []);
                for (let i = 0; i < total; i++) {
                    if (!collected.has(i)) uncollected.push({ id: p.id, idx: i, cols: p.cols, rows: p.rows });
                }
            }
            if (!uncollected.length) return null; // 全收集完

            const pick = uncollected[Math.floor(Math.random() * uncollected.length)];
            if (!data[pick.id]) data[pick.id] = { collected: [] };
            data[pick.id].collected.push(pick.idx);

            const total = pick.cols * pick.rows;
            const nowCollected = data[pick.id].collected.length;
            if (nowCollected >= total && !data[pick.id].completedAt) {
                data[pick.id].completedAt = Date.now();
            }
            saveGalleryData(data);
            return pick;
        }

        function showFragmentToast(piece) {
            const row = Math.floor(piece.idx / piece.cols);
            const col = piece.idx % piece.cols;
            const src = `paintings/${piece.id}/pieces/r${row}c${col}.jpg`;
            const toast = document.createElement('div');
            toast.className = 'fragment-toast';
            toast.innerHTML = `
                <div class="fragment-toast-thumb"><img src="${src}" alt=""></div>
                <div class="fragment-toast-text">
                    <strong>${t('gallery.fragment_drop')}</strong>
                    ${t('gallery.fragment_hint')}
                </div>`;
            document.body.appendChild(toast);
            setTimeout(() => toast.remove(), 3100);
        }

        function onWinDropFragment() {
            const winCount = recordDailyWin();
            if (winCount < 2) return; // 第一局不掉
            const piece = dropFragment();
            if (piece) showFragmentToast(piece);
        }

        // Gallery UI
        function openGallery() {
            const overlay = document.getElementById('gallery-overlay');
            if (!overlay) return;
            renderGalleryList();
            overlay.classList.add('show');
        }

        function closeGallery() {
            document.getElementById('gallery-overlay')?.classList.remove('show');
        }

        function closeGalleryDetail() {
            document.getElementById('gallery-detail-overlay')?.classList.remove('show');
        }

        function renderGalleryList() {
            const list = document.getElementById('gallery-list');
            if (!list) return;
            const data = loadGalleryData();
            list.innerHTML = '';

            const loadMeta = async (id) => {
                try {
                    const res = await fetch(`paintings/${id}/meta.json`);
                    return await res.json();
                } catch (_) { return null; }
            };

            (async () => {
                for (const p of PAINTINGS) {
                    const meta = await loadMeta(p.id);
                    if (!meta) continue;
                    const gd = data[p.id] || { collected: [] };
                    const collected = gd.collected.length;
                    const total = meta.totalPieces;
                    const pct = Math.round(collected / total * 100);
                    const isComplete = collected >= total;
                    const locale = currentLocale || 'en';
                    const title = (locale === 'en' || !meta.title) ? (meta.titleEn || meta.title) : meta.title;

                    const card = document.createElement('div');
                    card.className = `gallery-card${isComplete ? ' completed' : ''}`;
                    card.innerHTML = `
                        <div class="gallery-card-thumb ${meta.orientation}">
                            <img src="paintings/${p.id}/cover.jpg" alt="${title}">
                        </div>
                        <div class="gallery-card-info">
                            <div class="gallery-card-title">${title}</div>
                            <div class="gallery-progress-bar">
                                <div class="gallery-progress-fill" style="width:${pct}%"></div>
                            </div>
                            <div class="gallery-progress-text">${collected} / ${total} ${t('gallery.pieces')}</div>
                        </div>
                        <div class="gallery-card-lock">${isComplete ? '✦' : '○'}</div>`;
                    card.addEventListener('click', () => openGalleryDetail(meta, gd));
                    list.appendChild(card);
                }
            })();
        }

        function openGalleryDetail(meta, galleryData) {
            const overlay = document.getElementById('gallery-detail-overlay');
            const titleEl = document.getElementById('gallery-detail-title');
            const body = document.getElementById('gallery-detail-body');
            if (!overlay || !body) return;

            const locale = currentLocale || 'en';
            const title = (locale === 'en' || !meta.title) ? (meta.titleEn || meta.title) : meta.title;
            if (titleEl) titleEl.textContent = title;

            const collected = new Set(galleryData.collected || []);
            const total = meta.cols * meta.rows;
            const isComplete = collected.size >= total;

            body.innerHTML = '';

            if (isComplete) {
                // 完整畫作 + 畫框
                body.innerHTML = `
                    <div class="gallery-full-wrap">
                        <div class="gallery-frame">
                            <img src="paintings/${meta.id}/cover.jpg" alt="${title}">
                        </div>
                    </div>
                    <div class="gallery-detail-footer">
                        <div class="gallery-completed-label">${t('gallery.completed')}</div>
                    </div>`;
            } else {
                // 拼圖格
                const puzzle = document.createElement('div');
                puzzle.className = 'gallery-puzzle';
                // 依版型計算格子尺寸
                const maxW = Math.min(window.innerWidth * 0.88, 420);
                const pieceW = Math.floor((maxW - (meta.cols - 1) * 2) / meta.cols);
                const ratio = meta.rows / meta.cols;
                const pieceH = Math.floor(pieceW * (meta.orientation === 'portrait' ? 1.5 :
                                                      meta.orientation === 'landscape' ? 0.67 : 1));
                puzzle.style.gridTemplateColumns = `repeat(${meta.cols}, ${pieceW}px)`;

                for (let r = 0; r < meta.rows; r++) {
                    for (let c = 0; c < meta.cols; c++) {
                        const idx = r * meta.cols + c;
                        const isUnlocked = collected.has(idx);
                        const piece = document.createElement('div');
                        piece.className = `gallery-piece${isUnlocked ? '' : ' locked'}`;
                        piece.style.width = `${pieceW}px`;
                        piece.style.height = `${pieceH}px`;
                        piece.innerHTML = `<img src="paintings/${meta.id}/pieces/r${r}c${c}.jpg" alt="">`;
                        puzzle.appendChild(piece);
                    }
                }
                const wrap = document.createElement('div');
                wrap.className = 'gallery-puzzle-wrap';
                wrap.appendChild(puzzle);
                body.appendChild(wrap);

                const footer = document.createElement('div');
                footer.className = 'gallery-detail-footer';
                footer.innerHTML = `<div class="gallery-progress-text" style="text-align:center">${collected.size} / ${total} ${t('gallery.pieces')}</div>`;
                body.appendChild(footer);
            }
            overlay.classList.add('show');
        }
